CREATE TABLE transfer_job_rows (job_id VARCHAR(36) NOT NULL, source_row INT UNSIGNED NOT NULL, normalized_content JSON NOT NULL, PRIMARY KEY (job_id,source_row), CONSTRAINT fk_transfer_job_rows_job FOREIGN KEY (job_id) REFERENCES transfer_jobs (job_id) ON DELETE CASCADE, CONSTRAINT chk_transfer_job_rows_number CHECK (source_row BETWEEN 2 AND 100001)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
